public class CheckModelsBeforeGenerationAction extends ToggleAction {
  public CheckModelsBeforeGenerationAction() {
    super("Check Models Before Generation", "Check models for errors before generation", null);
  }
  @Override
  public boolean isSelected(AnActionEvent e) {
    MPSProject mpsProject = e.getData(MPSCommonDataKeys.MPS_PROJECT);
    return mpsProject != null && mpsProject.getComponent(GenerationSettingsProvider.class).getGenerationSettings().isCheckModelsBeforeGeneration();
  }
  @Override
  public void update(AnActionEvent e) {
    super.update(e);
    e.getPresentation().setEnabledAndVisible((e.getData(MPSCommonDataKeys.MPS_PROJECT)) != null);
  }
  @NotNull
  @Override
  public ActionUpdateThread getActionUpdateThread() {
    return ActionUpdateThread.BGT;
  }
  @Override
  public void setSelected(AnActionEvent e, boolean state) {
    MPSProject mpsProject = e.getData(MPSCommonDataKeys.MPS_PROJECT);
    assert mpsProject != null;
    GenerationSettingsProvider sp = mpsProject.getComponent(GenerationSettingsProvider.class);
    sp.getGenerationSettings().setCheckModelsBeforeGeneration(state);
  }
}
